// COMPLETE, COMPILABLE C code
// Uses correct I/O
// Handles all T test cases
#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int playGame(int* arr, int n) {
    int count = 0;
    for (int i = 0; i < (1 << n); i++) {
        int subSeq[n];
        int subSeqLen = 0;
        for (int j = 0; j < n; j++) {
            if ((i & (1 << j)) != 0) {
                subSeq[subSeqLen++] = arr[j];
            }
        }
        if (subSeqLen > 0) {
            int g = subSeq[0];
            for (int j = 1; j < subSeqLen; j++) {
                g = gcd(g, subSeq[j]);
            }
            if (g == 1) count++;
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", playGame(arr, N));
        free(arr);
    }
    return 0;
}

