#include <iostream>
#include <vector>
using namespace std;

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int playGame(vector<int>& arr) {
    int count = 0;
    int n = arr.size();
    for (int i = 0; i < (1 << n); i++) {
        vector<int> subSeq;
        for (int j = 0; j < n; j++) {
            if ((i & (1 << j)) != 0) {
                subSeq.push_back(arr[j]);
            }
        }
        if (subSeq.size() > 0) {
            int g = subSeq[0];
            for (int j = 1; j < subSeq.size(); j++) {
                g = gcd(g, subSeq[j]);
            }
            if (g == 1) count++;
        }
    }
    return count;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<int> arr(N);
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        cout << playGame(arr) << endl;
    }
    return 0;
}

